mapper.select:
select DISTINCT count(1) num ,b.tunnel_name tunnel_name,a.tunnel_id,
(select tunnel_name from t_tunnel_name_result where id = b.parent_id) parent_tunnel_name
from t_tunnel_notice a
LEFT JOIN t_tunnel_name_result b on a.tunnel_id = b.id
LEFT JOIN t_user_tunnel c on b.id = c.tunnel_name_id

    and a.type != 1 and a.process = 0

        and c.user_id = #{userId}



        and a.tunnel_id = #{tunnelId}



        and a.type = #{type}


GROUP BY a.tunnel_id,c.user_id

SELECT COALESCE(SUM(CASE WHEN a.type = 1 THEN 1 ELSE 0 END), 0) AS systemNotice, COALESCE(SUM(CASE WHEN a.type = 2 THEN 1 ELSE 0 END), 0) AS operationNotice, COALESCE(SUM(CASE WHEN a.type = 3 THEN 1 ELSE 0 END), 0) AS realtimeAlarm, COALESCE(SUM(CASE WHEN a.type = 4 THEN 1 ELSE 0 END), 0) AS deviceAlarm FROM t_tunnel_notice a
INNER JOIN t_user_tunnel u ON a.tunnel_id = u.tunnel_name_id AND u.user_id = #{userId}
WHERE a.process = 0 AND a.create_time >= DATE_SUB(NOW(), INTERVAL 7 DAY)

SELECT DATE_FORMAT(a.create_time, '%Y-%m-%d %H:%i:%s') AS time, a.content AS text, a.type AS type FROM t_tunnel_notice a
INNER JOIN t_user_tunnel u ON a.tunnel_id = u.tunnel_name_id AND u.user_id = #{userId}
WHERE a.type = #{type} AND a.process = 0 AND a.create_time >= DATE_SUB(NOW(), INTERVAL 7 DAY) ORDER BY a.create_time DESC LIMIT #{limit}

SELECT COUNT(1) FROM t_tunnel_notice a
INNER JOIN t_user_tunnel u ON a.tunnel_id = u.tunnel_name_id AND u.user_id = #{userId}
WHERE a.type = #{type} AND a.process = 0 AND a.create_time >= DATE_SUB(NOW(), INTERVAL 7 DAY)
